import { useNavigate } from "react-router-dom";
import { useAuth } from "../../Context/AuthContext";
import './Settings.css';

function settings() {
    const {isAuthenticated} = useAuth();
    const navigate = useNavigate();
    if (!isAuthenticated){
        navigate("/");
    }
    return (
        <>
        <div className="settings-container">
            <h1>Settings</h1>
        </div>
        </>
    )
};

export default settings;
